section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/freelancer-inbound-reply-template.json",
  "title": "Freelancer Inbound Reply Template",
  "type": "object",
  "required": [
    "artefact_id",
    "acknowledge_line",
    "qualifier_line",
    "trust_signal",
    "next_step",
    "channel",
    "sender_excerpt",
    "status",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "acknowledge_line": {
      "type": "string",
      "description": "single sentence acknowledging what the sender said",
      "minLength": 1
    },
    "qualifier_line": {
      "type": "string",
      "description": "smallest qualifier sentence \u2014 scope OR budget OR deadline",
      "minLength": 1
    },
    "trust_signal": {
      "type": "string",
      "description": "one verifiable proof point (portfolio link, prior client, metric)",
      "minLength": 1
    },
    "next_step": {
      "type": "string",
      "description": "single concrete next-step proposal (15-min call slot OR async question)",
      "minLength": 1
    },
    "channel": {
      "type": "string",
      "description": "linkedin|email|other",
      "minLength": 1
    },
    "sender_excerpt": {
      "type": "string",
      "description": "verbatim 1-2 sentence quote of the inbound that justifies the qualifier",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
